import{_ as t,o as a,c as s,ag as n}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Architecture Overview","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/architecture-overview.md","filePath":"architecture/architecture-overview.md","lastUpdated":1775719799000}'),o={name:"architecture/architecture-overview.md"};function i(d,e,r,c,p,l){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h1><p><strong>Last updated:</strong> 2026-03-22 <strong>Source docs consolidated:</strong> <code>docs/architecture.md</code>, <code>docs/websocket_architecture.md</code></p><hr><h2 id="_1-system-overview" tabindex="-1">1. System Overview <a class="header-anchor" href="#_1-system-overview" aria-label="Permalink to &quot;1. System Overview&quot;">​</a></h2><p>rustchat is a self-hosted team collaboration platform composed of 3 runtime services and 1 offline analysis tool:</p><table tabindex="0"><thead><tr><th>Service</th><th>Language</th><th>Purpose</th></tr></thead><tbody><tr><td><code>backend</code></td><td>Rust (Axum 0.8 + Tokio)</td><td>HTTP API, WebSocket hub, business logic, DB</td></tr><tr><td><code>frontend</code></td><td>Vue 3.5 + TypeScript + Pinia</td><td>Single-page web application</td></tr><tr><td><code>push-proxy</code></td><td>Rust</td><td>Mobile push notification gateway (FCM/APNS)</td></tr><tr><td><code>tools/mm-compat</code></td><td>Python</td><td>Offline Mattermost compatibility analysis tooling</td></tr></tbody></table><p><strong>External dependencies:</strong></p><table tabindex="0"><thead><tr><th>Dependency</th><th>Purpose</th><th>Required</th></tr></thead><tbody><tr><td>PostgreSQL 16+</td><td>Primary data store</td><td>Yes</td></tr><tr><td>Redis 7+</td><td>Pub/sub for cross-instance events, rate limiting, sessions</td><td>Yes</td></tr><tr><td>S3-compatible (RustFS/MinIO)</td><td>File storage</td><td>Yes</td></tr><tr><td>FCM / APNS</td><td>Mobile push notifications (via push-proxy)</td><td>Optional</td></tr><tr><td>SMTP</td><td>Email notifications, password reset</td><td>Optional</td></tr><tr><td>OAuth providers</td><td>SSO login (configurable)</td><td>Optional</td></tr></tbody></table><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                        Web / SPA Client                            │</span></span>
<span class="line"><span>│                  (Vue 3.5 + TypeScript + Pinia)                    │</span></span>
<span class="line"><span>└──────────────────────────────┬─────────────────────────────────────┘</span></span>
<span class="line"><span>                               │ REST + WebSocket</span></span>
<span class="line"><span>                               ▼</span></span>
<span class="line"><span>┌────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                      rustchat API Server                           │</span></span>
<span class="line"><span>│                      (Axum 0.8 + Tokio)                            │</span></span>
<span class="line"><span>│                                                                    │</span></span>
<span class="line"><span>│  /api/v1/*  ──── native API (internal clients)                     │</span></span>
<span class="line"><span>│  /api/v4/*  ──── Mattermost-compatible API (mobile/desktop clients)│</span></span>
<span class="line"><span>│                                                                    │</span></span>
<span class="line"><span>│  ┌──────────────────────────────────────────────────────────────┐  │</span></span>
<span class="line"><span>│  │                     Service Layer                            │  │</span></span>
<span class="line"><span>│  │  auth · channels · posts · files · realtime · jobs · a2a    │  │</span></span>
<span class="line"><span>│  └──────────────────────┬───────────────────────────────────────┘  │</span></span>
<span class="line"><span>└─────────────────────────┼──────────────────────────────────────────┘</span></span>
<span class="line"><span>                          │</span></span>
<span class="line"><span>        ┌─────────────────┼─────────────────┐</span></span>
<span class="line"><span>        ▼                 ▼                 ▼</span></span>
<span class="line"><span>   PostgreSQL           Redis           S3-compatible</span></span>
<span class="line"><span>   (primary data)    (events/cache)     (file storage)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────────────────────────────┐</span></span>
<span class="line"><span>│       push-proxy             │</span></span>
<span class="line"><span>│  (Rust, separate service)    │</span></span>
<span class="line"><span>│  Receives events from        │</span></span>
<span class="line"><span>│  backend → delivers to       │</span></span>
<span class="line"><span>│  FCM (Android) / APNS (iOS)  │</span></span>
<span class="line"><span>└──────────────────────────────┘</span></span></code></pre></div><hr><h2 id="_2-backend" tabindex="-1">2. Backend <a class="header-anchor" href="#_2-backend" aria-label="Permalink to &quot;2. Backend&quot;">​</a></h2><p><strong>Stack:</strong> Rust, Axum 0.8, Tokio, SQLx (compile-time checked queries), Tower middleware</p><p><strong>Top-level module structure</strong> (<code>backend/src/</code>):</p><table tabindex="0"><thead><tr><th>Module</th><th>Responsibility</th></tr></thead><tbody><tr><td><code>a2a/</code></td><td>Agent-to-agent communication layer</td></tr><tr><td><code>api/</code></td><td>HTTP handlers: v1 native API + v4 Mattermost-compatible API</td></tr><tr><td><code>auth/</code></td><td>Authentication: JWT generation/validation, password hashing (Argon2id)</td></tr><tr><td><code>config/</code></td><td>Environment-based configuration (the <code>config</code> crate)</td></tr><tr><td><code>db/</code></td><td>PostgreSQL connection pool, SQLx macros, migration runner</td></tr><tr><td><code>error/</code></td><td>Structured error types with HTTP status mapping</td></tr><tr><td><code>jobs/</code></td><td>Background job workers (async task queue)</td></tr><tr><td><code>mattermost_compat/</code></td><td>Mattermost-specific response transformation utilities</td></tr><tr><td><code>middleware/</code></td><td>Axum middleware: auth extraction, rate limiting, logging, CORS</td></tr><tr><td><code>models/</code></td><td>Data models: User, Channel, Post, Team, File, Entity, etc.</td></tr><tr><td><code>realtime/</code></td><td>WebSocket hub: connection management, event fan-out, cluster broadcast via Redis</td></tr><tr><td><code>services/</code></td><td>Business logic: one service per domain area (channels, posts, files, …)</td></tr><tr><td><code>storage/</code></td><td>S3-compatible file upload/download</td></tr><tr><td><code>telemetry/</code></td><td>Structured JSON logging with <code>tracing</code></td></tr></tbody></table><p>Note: <code>channels</code> and <code>posts</code> are sub-modules under <code>api/v1/</code> and <code>services/</code>, not top-level modules.</p><p><strong>Request lifecycle:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Request → Middleware (auth, rate-limit, CORS) → Router → Handler → Service → DB/Storage</span></span>
<span class="line"><span>                                                                           ↓</span></span>
<span class="line"><span>Response ← JSON serialization ← Result&lt;T, AppError&gt;</span></span></code></pre></div><p><strong>Migrations:</strong> <code>backend/migrations/</code> — SQLx numbered migrations, run automatically at startup. Irreversible — see <code>.governance/pr-size-limits.yml</code> for migration PR size constraints.</p><h3 id="websocket-hub" tabindex="-1">WebSocket Hub <a class="header-anchor" href="#websocket-hub" aria-label="Permalink to &quot;WebSocket Hub&quot;">​</a></h3><p>Two WebSocket endpoints share a common core (<code>api/websocket_core.rs</code>) but present different wire formats:</p><table tabindex="0"><thead><tr><th>Endpoint</th><th>Clients</th><th>Wire format</th></tr></thead><tbody><tr><td><code>/api/v1/ws</code></td><td>rustchat web app, internal clients</td><td>Internal envelope (<code>type</code>, <code>event</code>, <code>data</code>, <code>channel_id</code>)</td></tr><tr><td><code>/api/v4/websocket</code></td><td>Mattermost mobile/desktop clients</td><td>Mattermost framing (<code>event</code>, <code>data</code>, <code>broadcast</code>, <code>seq</code>)</td></tr></tbody></table><p><strong>Shared core handles:</strong></p><ul><li>Auth token normalization (header + <code>Sec-WebSocket-Protocol</code> fallback)</li><li>Connection limit enforcement</li><li>Default team/channel subscription bootstrap</li><li>Presence lifecycle: <code>online</code> on connect, <code>offline</code> when last connection drops</li><li>Shared commands: <code>subscribe_channel</code>, <code>unsubscribe_channel</code>, <code>typing</code>, <code>presence</code>, <code>ping</code>→<code>pong</code></li></ul><p><strong>v4-specific behavior:</strong></p><ul><li>Optional auth challenge exchange (<code>action=authentication_challenge</code>)</li><li>Session resumption (<code>connection_id</code>, <code>sequence_number</code>)</li><li>Mattermost event name mapping: <code>posted</code>, <code>typing</code>, <code>post_edited</code>, <code>status_change</code>, etc.</li></ul><p><strong>Event fan-out:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Service writes event → realtime::hub → broadcast to subscribed connections</span></span>
<span class="line"><span>                                    → Redis pub/sub → other backend instances → their hubs</span></span></code></pre></div><p><strong>Client-side Connection State Management:</strong></p><p>The frontend implements progressive disconnection UX to handle network interruptions gracefully:</p><table tabindex="0"><thead><tr><th>State</th><th>Duration</th><th>Visual</th><th>Behavior</th></tr></thead><tbody><tr><td><code>connected</code></td><td>—</td><td>🟢 Green dot</td><td>Normal operation</td></tr><tr><td><code>reconnecting</code></td><td>&lt; 5s</td><td>🟡 Yellow banner, 80% opacity</td><td>Auto-retry with backoff</td></tr><tr><td><code>disconnected</code></td><td>5-30s</td><td>🟠 Orange banner, 60% opacity</td><td>Manual retry option</td></tr><tr><td><code>failed</code></td><td>&gt; 30s</td><td>🔴 Full-screen modal</td><td>Explicit reconnect required</td></tr></tbody></table><p><strong>State transitions:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CONNECTED → onClose → RECONNECTING (auto-retry, exponential backoff)</span></span>
<span class="line"><span>RECONNECTING → timeout 5s → DISCONNECTED (manual retry available)</span></span>
<span class="line"><span>DISCONNECTED → timeout 30s → FAILED (must reconnect or refresh)</span></span></code></pre></div><p>See <code>SPEC-WEBSOCKET-DISCONNECTION-UX.md</code> for full specification.</p><hr><h2 id="_3-frontend" tabindex="-1">3. Frontend <a class="header-anchor" href="#_3-frontend" aria-label="Permalink to &quot;3. Frontend&quot;">​</a></h2><p><strong>Stack:</strong> Vue 3.5, TypeScript, Pinia (state), Vue Router, Vite (build)</p><p><strong>Directory structure:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>frontend/src/</span></span>
<span class="line"><span>├── core/          # Shared primitives: entities, errors, websocket infrastructure</span></span>
<span class="line"><span>├── features/      # 14 domain feature modules (auth, calls, channels, messages, …)</span></span>
<span class="line"><span>├── api/           # API client functions</span></span>
<span class="line"><span>├── components/    # Vue components</span></span>
<span class="line"><span>├── composables/   # Vue composables</span></span>
<span class="line"><span>└── stores/        # Legacy Pinia stores (deprecated, being migrated to features/)</span></span></code></pre></div><p><strong>Feature module pattern</strong> — every feature follows the same layers:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>features/[feature]/</span></span>
<span class="line"><span>├── repositories/    # Data access (API calls)</span></span>
<span class="line"><span>├── services/        # Business logic</span></span>
<span class="line"><span>├── stores/          # Pinia state (no business logic)</span></span>
<span class="line"><span>├── handlers/        # WebSocket event handlers</span></span>
<span class="line"><span>└── index.ts         # Public API</span></span></code></pre></div><p><strong>E2E tests:</strong> Playwright snapshot tests in <code>frontend/e2e/</code>. Run with <code>cd frontend &amp;&amp; npx playwright test</code>.</p><hr><h2 id="_4-push-proxy" tabindex="-1">4. Push Proxy <a class="header-anchor" href="#_4-push-proxy" aria-label="Permalink to &quot;4. Push Proxy&quot;">​</a></h2><p>Separate Rust service (<code>push-proxy/</code>). Receives push notification events from the backend via an internal HTTP call and forwards them to FCM (Android) or APNS (iOS). Deployed separately from the main backend to isolate credential scope.</p><hr><h2 id="_5-mattermost-compatibility-surface" tabindex="-1">5. Mattermost Compatibility Surface <a class="header-anchor" href="#_5-mattermost-compatibility-surface" aria-label="Permalink to &quot;5. Mattermost Compatibility Surface&quot;">​</a></h2><p>The compatibility surface is the set of paths that external Mattermost clients depend on. Changes here require compat-reviewer co-approval (see <code>CODEOWNERS</code>):</p><table tabindex="0"><thead><tr><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><code>backend/src/api/v4/</code></td><td>Mattermost HTTP API v4 handlers</td></tr><tr><td><code>backend/src/mattermost_compat/</code></td><td>Response transformation, field mapping utilities</td></tr><tr><td><code>backend/compat/</code></td><td>Contract JSON schemas + contract validation tests</td></tr><tr><td><code>backend/src/realtime/</code></td><td>WebSocket hub (v4 event contracts)</td></tr></tbody></table><p>For coverage details see <code>docs/compatibility-scope.md</code>.</p><hr><h2 id="_6-data-flow" tabindex="-1">6. Data Flow <a class="header-anchor" href="#_6-data-flow" aria-label="Permalink to &quot;6. Data Flow&quot;">​</a></h2><h3 id="http-request-lifecycle" tabindex="-1">HTTP Request Lifecycle <a class="header-anchor" href="#http-request-lifecycle" aria-label="Permalink to &quot;HTTP Request Lifecycle&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client → [Nginx proxy, port 8080 in Docker] → Axum Router (port 3000) → Middleware (auth, rate-limit, CORS)</span></span>
<span class="line"><span>       → Handler → Service → DB / Storage</span></span>
<span class="line"><span>       ← JSON response ← Result&lt;T, AppError&gt;</span></span></code></pre></div><h3 id="websocket-event-flow" tabindex="-1">WebSocket Event Flow <a class="header-anchor" href="#websocket-event-flow" aria-label="Permalink to &quot;WebSocket Event Flow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Service writes event</span></span>
<span class="line"><span>  → realtime::hub</span></span>
<span class="line"><span>  → broadcast to subscribed local connections</span></span>
<span class="line"><span>  → Redis pub/sub → other backend instances → their hubs → their connections</span></span></code></pre></div><h3 id="frontend-data-flow" tabindex="-1">Frontend Data Flow <a class="header-anchor" href="#frontend-data-flow" aria-label="Permalink to &quot;Frontend Data Flow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Component → Store → Service → Repository → API (HTTP)</span></span>
<span class="line"><span>                ↑</span></span>
<span class="line"><span>WebSocket → Handler → Service → Store update</span></span></code></pre></div><hr><h2 id="_7-key-design-decisions" tabindex="-1">7. Key Design Decisions <a class="header-anchor" href="#_7-key-design-decisions" aria-label="Permalink to &quot;7. Key Design Decisions&quot;">​</a></h2><ul><li><strong>Axum over Actix-web:</strong> Tower middleware ecosystem, async-first, ergonomic extractors.</li><li><strong>Separate push-proxy service:</strong> Isolates FCM/APNS credentials; can be scaled/deployed independently.</li><li><strong>Redis for cross-instance fan-out:</strong> Enables horizontal scaling of API servers without sticky sessions.</li><li><strong>SQLx compile-time query checks:</strong> Prevents schema/query drift at the cost of requiring a live DB at compile time (see <code>SQLX_OFFLINE</code> flag for CI).</li><li><strong>Two WebSocket endpoints (v1 + v4):</strong> Avoids breaking the native web app while maintaining Mattermost client compatibility. Shared core prevents logic drift between them.</li><li><strong>Feature-based frontend structure:</strong> Avoids the 960-line store antipattern; enforces single responsibility (avg 105 lines/file post-refactor).</li></ul>`,60)])])}const b=t(o,[["render",i]]);export{u as __pageData,b as default};
